class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private lateinit var jsBridge: JavaScriptBridge
    private lateinit var cameraLauncher: ActivityResultLauncher<Intent>
    private lateinit var permissionLauncher: ActivityResultLauncher<Array<String>>
    private var photoUri: Uri? = null
    private var pendingCallback: String? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)
        
        setupActivityResultLaunchers()
        setupWebView()
        
        val url = "https://your-web-app-url.com"
        webView.loadUrl(url)
    }

    private fun setupActivityResultLaunchers() {
        cameraLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                photoUri?.let { uri ->
                    pendingCallback?.let { callback ->
                        jsBridge.handleCameraResult(callback, uri.toString())
                    }
                }
            } else {
                pendingCallback?.let { callback ->
                    jsBridge.handleCameraError(callback, "Camera cancelled")
                }
            }
            pendingCallback = null
            photoUri = null
        }

        permissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestMultiplePermissions()
        ) { permissions ->
            val allGranted = permissions.values.all { it }
            if (allGranted) {
                pendingCallback?.let { callback ->
                    jsBridge.handlePermissionResult(callback, true)
                }
            } else {
                pendingCallback?.let { callback ->
                    jsBridge.handlePermissionResult(callback, false)
                }
            }
            pendingCallback = null
        }
    }

    private fun setupWebView() {
        jsBridge = JavaScriptBridge(this, webView)
        
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = false
            allowContentAccess = true
            mixedContentMode = WebSettings.MIXED_CONTENT_NEVER_ALLOW
            
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                safeBrowsingEnabled = true
            }
        }

        webView.addJavascriptInterface(jsBridge, "NativeBridge")
        
        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                val url = request?.url?.toString() ?: return false
                
                if (url.startsWith("https://your-web-app-url.com")) {
                    return false
                }
                
                return true
            }

            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
            }

            override fun onReceivedError(view: WebView?, request: WebResourceRequest?, error: WebResourceError?) {
                super.onReceivedError(view, request, error)
            }

            override fun onReceivedSslError(view: WebView?, handler: SslErrorHandler?, error: SslError?) {
                handler?.cancel()
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                return true
            }

            override fun onJsAlert(view: WebView?, url: String?, message: String?, result: JsResult?): Boolean {
                return super.onJsAlert(view, url, message, result)
            }
        }
    }

    fun launchCamera(callback: String) {
        pendingCallback = callback
        
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) 
            != PackageManager.PERMISSION_GRANTED) {
            permissionLauncher.launch(arrayOf(Manifest.permission.CAMERA))
            return
        }

        val photoFile = createImageFile()
        photoUri = FileProvider.getUriForFile(
            this,
            "${applicationContext.packageName}.fileprovider",
            photoFile
        )

        val intent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, photoUri)
        }
        
        cameraLauncher.launch(intent)
    }

    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir = getExternalFilesDir(null)
        return File.createTempFile("JPEG_${timeStamp}_", ".jpg", storageDir)
    }

    fun requestPermissions(permissions: Array<String>, callback: String) {
        pendingCallback = callback
        permissionLauncher.launch(permissions)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    override fun onDestroy() {
        webView.removeJavascriptInterface("NativeBridge")
        webView.destroy()
        super.onDestroy()
    }
}

class JavaScriptBridge(
    private val activity: MainActivity,
    private val webView: WebView
) {
    private val context: Context = activity.applicationContext
    private val sharedPrefs = context.getSharedPreferences("AppStorage", Context.MODE_PRIVATE)

    @JavascriptInterface
    fun openCamera(callback: String) {
        activity.runOnUiThread {
            activity.launchCamera(callback)
        }
    }

    @JavascriptInterface
    fun saveToStorage(key: String, value: String, callback: String) {
        try {
            val sanitizedKey = sanitizeKey(key)
            if (sanitizedKey.isEmpty() || sanitizedKey.length > 100) {
                executeCallback(callback, createErrorResponse("Invalid key"))
                return
            }

            if (value.length > 1024 * 1024) {
                executeCallback(callback, createErrorResponse("Value too large"))
                return
            }

            sharedPrefs.edit().putString(sanitizedKey, value).apply()
            executeCallback(callback, createSuccessResponse("Data saved"))
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Storage error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun getFromStorage(key: String, callback: String) {
        try {
            val sanitizedKey = sanitizeKey(key)
            if (sanitizedKey.isEmpty() || sanitizedKey.length > 100) {
                executeCallback(callback, createErrorResponse("Invalid key"))
                return
            }

            val value = sharedPrefs.getString(sanitizedKey, null)
            if (value != null) {
                val response = JSONObject().apply {
                    put("success", true)
                    put("data", value)
                }
                executeCallback(callback, response.toString())
            } else {
                executeCallback(callback, createErrorResponse("Key not found"))
            }
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Storage error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun removeFromStorage(key: String, callback: String) {
        try {
            val sanitizedKey = sanitizeKey(key)
            if (sanitizedKey.isEmpty() || sanitizedKey.length > 100) {
                executeCallback(callback, createErrorResponse("Invalid key"))
                return
            }

            sharedPrefs.edit().remove(sanitizedKey).apply()
            executeCallback(callback, createSuccessResponse("Data removed"))
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Storage error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun clearStorage(callback: String) {
        try {
            sharedPrefs.edit().clear().apply()
            executeCallback(callback, createSuccessResponse("Storage cleared"))
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Storage error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun requestPushPermission(callback: String) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            activity.requestPermissions(
                arrayOf(Manifest.permission.POST_NOTIFICATIONS),
                callback
            )
        } else {
            executeCallback(callback, createSuccessResponse("Permission granted"))
        }
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String, callback: String) {
        try {
            val sanitizedTopic = sanitizeTopic(topic)
            if (sanitizedTopic.isEmpty() || sanitizedTopic.length > 100) {
                executeCallback(callback, createErrorResponse("Invalid topic"))
                return
            }

            FirebaseMessaging.getInstance().subscribeToTopic(sanitizedTopic)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        executeCallback(callback, createSuccessResponse("Subscribed to topic"))
                    } else {
                        executeCallback(callback, createErrorResponse("Subscription failed"))
                    }
                }
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Push error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String, callback: String) {
        try {
            val sanitizedTopic = sanitizeTopic(topic)
            if (sanitizedTopic.isEmpty() || sanitizedTopic.length > 100) {
                executeCallback(callback, createErrorResponse("Invalid topic"))
                return
            }

            FirebaseMessaging.getInstance().unsubscribeFromTopic(sanitizedTopic)
                .addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        executeCallback(callback, createSuccessResponse("Unsubscribed from topic"))
                    } else {
                        executeCallback(callback, createErrorResponse("Unsubscription failed"))
                    }
                }
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Push error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun getPushToken(callback: String) {
        try {
            FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val token = task.result
                    val response = JSONObject().apply {
                        put("success", true)
                        put("token", token)
                    }
                    executeCallback(callback, response.toString())
                } else {
                    executeCallback(callback, createErrorResponse("Failed to get token"))
                }
            }
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Push error: ${e.message}"))
        }
    }

    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            val sanitizedMessage = message.take(200)
            Toast.makeText(context, sanitizedMessage, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun getDeviceInfo(callback: String) {
        try {
            val deviceInfo = JSONObject().apply {
                put("success", true)
                put("data", JSONObject().apply {
                    put("platform", "Android")
                    put("version", Build.VERSION.RELEASE)
                    put("model", Build.MODEL)
                    put("manufacturer", Build.MANUFACTURER)
                })
            }
            executeCallback(callback, deviceInfo.toString())
        } catch (e: Exception) {
            executeCallback(callback, createErrorResponse("Error getting device info"))
        }
    }

    fun handleCameraResult(callback: String, imageUri: String) {
        val response = JSONObject().apply {
            put("success", true)
            put("imageUri", imageUri)
        }
        executeCallback(callback, response.toString())
    }

    fun handleCameraError(callback: String, error: String) {
        executeCallback(callback, createErrorResponse(error))
    }

    fun handlePermissionResult(callback: String, granted: Boolean) {
        if (granted) {
            executeCallback(callback, createSuccessResponse("Permission granted"))
        } else {
            executeCallback(callback, createErrorResponse("Permission denied"))
        }
    }

    private fun executeCallback(callback: String, response: String) {
        val sanitizedCallback = sanitizeCallback(callback)
        if (sanitizedCallback.isEmpty()) return

        activity.runOnUiThread {
            val escapedResponse = response.replace("'", "\\'")
            val script = "$sanitizedCallback('$escapedResponse');"
            webView.evaluateJavascript(script, null)
        }
    }

    private fun createSuccessResponse(message: String): String {
        return JSONObject().apply {
            put("success", true)
            put("message", message)
        }.toString()
    }

    private fun createErrorResponse(error: String): String {
        return JSONObject().apply {
            put("success", false)
            put("error", error)
        }.toString()
    }

    private fun sanitizeKey(key: String): String {
        return key.replace(Regex("[^a-zA-Z0-9_-]"), "")
    }

    private fun sanitizeTopic(topic: String): String {
        return topic.replace(Regex("[^a-zA-Z0-9_-]"), "")
    }

    private fun sanitizeCallback(callback: String): String {
        return if (callback.matches(Regex("^[a-zA-Z_][a-zA-Z0-9_.]*$"))) {
            callback
        } else {
            ""
        }
    }
}

class MyFirebaseMessagingService : com.google.firebase.messaging.FirebaseMessagingService() {
    override fun onMessageReceived(remoteMessage: com.google.firebase.messaging.RemoteMessage) {
        super.onMessageReceived(remoteMessage)
        
        remoteMessage.notification?.let {
            val title = it.title ?: "Notification"
            val body = it.body ?: ""
            showNotification(title, body)
        }
    }

    override fun onNewToken(token: String) {
        super.onNewToken(token)
    }

    private fun showNotification(title: String, message: String) {
        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as android.app.NotificationManager
        val channelId = "default_channel"

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = android.app.NotificationChannel(
                channelId,
                "Default Channel",
                android.app.NotificationManager.IMPORTANCE_DEFAULT
            )
            notificationManager.createNotificationChannel(channel)
        }

        val notification = androidx.core.app.NotificationCompat.Builder(this, channelId)
            .setContentTitle(title)
            .setContentText(message)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setAutoCancel(true)
            .build()

        notificationManager.notify(System.currentTimeMillis().toInt(), notification)
    }
}